class NestedIterator {
public:
    NestedIterator(vector<NestedInteger> &nestedList) {
        flatten(nestedList);
    }

    int next() {
        int result = queue.front();
        queue.pop();
        return result;
    }

    bool hasNext() {
        return !queue.empty();
    }
private:
    queue<int> queue;

    void flatten(const vector<NestedInteger> &nestedList) {
        for (const auto &ni : nestedList) {
            if (ni.isInteger()) {
                queue.push(ni.getInteger());
            } else {
                flatten(ni.getList());
            }
        }
    }
};

